}

.mist-1 {
  width: 320rpx;
  height: 120rpx;
  top: 120rpx;
  left: -30rpx;
  animation: mistFlow 9s ease-in-out infinite;
}

.mist-2 {
  width: 360rpx;
  height: 140rpx;
  top: 560rpx;
  right: -60rpx;
  animation: mistFlow 11s ease-in-out infinite reverse;
}

