}

.forest-scene,
.energy-card,
.card {
  margin-bottom: 24rpx;
  border-radius: var(--pf-radius-card);
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 12rpx 30rpx rgba(66, 133, 92, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.65);
}

.forest-scene {
  position: relative;
  overflow: hidden;
  min-height: 470rpx;
  background: linear-gradient(180deg, #c9eed8 0%, #effcf4 100%);
}

.scene-sky {
