  z-index: 3;
}

.scene-ground {
  position: absolute;
  left: -10%;
  right: -10%;
  bottom: -56rpx;
  height: 220rpx;
  border-radius: 50%;
  background: radial-gradient(ellipse at center, #81d397 0%, #62b97c 64%, #4ca566 100%);
  z-index: 2;
}

.sun {
  position: absolute;
  top: 34rpx;
  right: 44rpx;
  width: 76rpx;
  height: 76rpx;
  border-radius: 38rpx;
  background: radial-gradient(circle, #fff3a5 0%, #ffd965 75%, #f6c847 100%);
  box-shadow: 0 0 32rpx rgba(255, 214, 112, 0.8);
  z-index: 2;
  animation: sunFloat 4.8s ease-in-out infinite;
}

.cloud {
  position: absolute;
  height: 28rpx;
  border-radius: 20rpx;
  background: rgba(255, 255, 255, 0.86);
  z-index: 2;
  box-shadow: 0 6rpx 16rpx rgba(255, 255, 255, 0.2);
}

.cloud-left {
  width: 100rpx;
  top: 66rpx;
  left: 42rpx;
  animation: cloudDriftLeft 8s ease-in-out infinite;
}

.cloud-right {
  width: 130rpx;
  top: 116rpx;
  right: 130rpx;
  animation: cloudDriftRight 9s ease-in-out infinite;
}

.hero-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.hero-title {
  font-size: 36rpx;
  font-weight: 700;
  color: var(--pf-color-text-main);
}

.hero-badge {
  padding: 8rpx 18rpx;
  background: rgba(71, 175, 99, 0.16);
  color: #3f8654;
  border-radius: var(--pf-radius-pill);
  font-size: 22rpx;
  font-weight: 600;
}

.hero-plant {
  margin-top: 16rpx;
  font-size: 42rpx;
  font-weight: 700;
  color: var(--pf-color-primary-dark);
  text-align: center;
}

.plant-stage {
  position: relative;
  width: 100%;
  display: flex;
  justify-content: center;
  margin-top: 8rpx;
}

.hero-image {
  width: 214rpx;
  height: 214rpx;
  position: relative;
  z-index: 4;
  filter: drop-shadow(0 14rpx 16rpx rgba(50, 122, 73, 0.22));
}

.hero-image.pulse {
  animation: heroPulse 520ms ease;
}

.glow-ring {
  position: absolute;
  bottom: 8rpx;
  width: 220rpx;
  height: 44rpx;
  border-radius: 50%;
  background: rgba(70, 175, 99, 0.24);
  z-index: 3;
}

.glow-ring.glow {
  animation: ringGlow 700ms ease;
}

.float-score {
  position: absolute;
  top: 26rpx;
  right: 180rpx;
  z-index: 5;
  color: #2a9a4d;
  font-size: 40rpx;
  font-weight: 700;
  text-shadow: 0 4rpx 12rpx rgba(62, 145, 86, 0.3);
  animation: floatUp 900ms ease forwards;
}

.stage-up-tip {
  position: absolute;
  top: -4rpx;
  left: 50%;
  transform: translateX(-50%);
  z-index: 5;
  padding: 8rpx 18rpx;
  border-radius: 999rpx;
  background: linear-gradient(90deg, #ffd35d, #ffb347);
  color: #7a4e12;
  font-size: 24rpx;
  font-weight: 700;
  box-shadow: 0 6rpx 16rpx rgba(255, 191, 87, 0.45);
  animation: stagePop 1200ms ease forwards;
}

.hero-desc {
  margin-top: 8rpx;
  color: #6d8673;
  font-size: 24rpx;
  text-align: center;
}

.energy-card {
  padding: 24rpx 26rpx;
  backdrop-filter: blur(8rpx);
}
.panel-card {
  padding:20rpx;
}
.panel-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 14rpx;
}

.panel-card .panel-head {
  margin-bottom: 18rpx;
}

.panel-title-wrap {
  display: flex;
  align-items: center;
}

.panel-dot {
  width: 14rpx;
  height: 14rpx;
  border-radius: 7rpx;
  margin-right: 10rpx;
  background: linear-gradient(180deg, #5ec57c 0%, #3da85e 100%);
  box-shadow: 0 0 10rpx rgba(79, 186, 108, 0.35);
}

.panel-title {
  font-size: 30rpx;
  font-weight: 700;
  color: var(--pf-color-text-main);
}

.panel-meta {
  font-size: 22rpx;
  color: #6f8a76;
  padding: 6rpx 14rpx;
  border-radius: 999rpx;
  background: #edf7f0;
  border: 1px solid #dcf0e2;
}

.energy-label {
  font-size: 28rpx;
  color: #355f44;
  font-weight: 600;
}

.energy-value {
  font-size: 26rpx;
  color: #4c8a5e;
  font-weight: 600;
}

.progress-bg {
  margin-top: 12rpx;
  height: 18rpx;
  border-radius: 999rpx;
  background: linear-gradient(90deg, #e3f0e5 0%, #edf7ef 100%);
  overflow: hidden;
}

.progress-bar {
  height: 18rpx;
  border-radius: var(--pf-radius-pill);
  background: linear-gradient(90deg, #74cf8d, #4dbd6e 55%, #3ea55d 100%);
  box-shadow: 0 0 12rpx rgba(74, 188, 108, 0.34);
}

.stage-hint {
  margin-top: 10rpx;
  color: #7a9280;
  font-size: 22rpx;
}

.stats-grid {
  margin-top: 20rpx;
  display: flex;
  gap: 16rpx;
}

.stats-item {
  flex: 1;
  background: linear-gradient(180deg, #f6fcf8 0%, #edf8f0 100%);
  border-radius: 16rpx;
  text-align: center;
  padding: 18rpx 0;
  border: 1px solid #e6f3e9;
}

.stats-value {
  font-size: 38rpx;
  font-weight: 700;
  color: var(--pf-color-primary-dark);
}

.stats-label {
  margin-top: 6rpx;
  font-size: 22rpx;
  color: #7d8f81;
}

.action-panel {
  padding-bottom: 22rpx;
}

.action-grid {
  display: flex;
  gap: 14rpx;
}

.action-bubble {
  flex: 1;
  border-radius: 24rpx;
  background: linear-gradient(180deg, #f4fcf7 0%, #e8f6ed 100%);
