}

.action-bubble:active {
  transform: translateY(2rpx) scale(0.98);
}

.action-bubble.disabled {
  opacity: 0.58;
}

.bubble-icon {
  font-size: 38rpx;
}

.bubble-name {
  margin-top: 8rpx;
  font-size: 24rpx;
  font-weight: 600;
  color: #2f5f3c;
}

.bubble-score {
  margin-top: 4rpx;
  font-size: 28rpx;
  color: #39a35a;
  font-weight: 700;
}

.bubble-count {
  margin-top: 4rpx;
  font-size: 21rpx;
  color: #86a08d;
}

.flower-scroll {
  white-space: nowrap;

}

.flower-list {
  display: inline-flex;
  gap: 14rpx;
  padding-bottom: 6rpx;
}

.flower-item {
  min-width: 196rpx;
  border-radius: 16rpx;
  border: 2rpx solid #dbeee1;
  background: linear-gradient(180deg, #f8fcf9 0%, #f0f8f2 100%);
  padding: 16rpx;
  box-shadow: 0 8rpx 14rpx rgba(88, 145, 106, 0.1);
}

.flower-image {
  width: 92rpx;
  height: 92rpx;
  display: block;
  margin: 0 auto 10rpx;
}

.flower-item.active {
  border-color: #58b875;
  background: linear-gradient(180deg, #eefbf1 0%, #e2f5e8 100%);
  box-shadow: 0 10rpx 18rpx rgba(71, 173, 99, 0.2);
}

.flower-name {
  font-size: 28rpx;
  color: #2f5f3c;
  font-weight: 600;
}

.flower-stage {
  margin-top: 8rpx;
  display: inline-block;
  padding: 4rpx 12rpx;
  border-radius: 999rpx;
  font-size: 20rpx;
  color: #5a8b67;
  background: #e4f4e8;
}

.flower-growth {
  margin-top: 10rpx;
  font-size: 22rpx;
  color: #7c9382;
}

.tip {
  margin-top: 14rpx;
  color: #8ca18f;
  font-size: 24rpx;
  text-align: center;
}

@keyframes heroPulse {
  0% {
    transform: scale(1);
  }
  45% {
    transform: scale(1.09);
  }
  100% {
    transform: scale(1);
  }
}

@keyframes cloudDriftLeft {
  0% {
    transform: translateX(0);
  }
  50% {
    transform: translateX(10rpx);
  }
  100% {
    transform: translateX(0);
  }
}

@keyframes cloudDriftRight {
  0% {
    transform: translateX(0);
  }
  50% {
    transform: translateX(-12rpx);
  }
  100% {
    transform: translateX(0);
  }
}

@keyframes sunFloat {
  0% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-5rpx);
  }
  100% {
    transform: translateY(0);
  }
}

@keyframes mistFlow {
  0% {
    transform: translateX(0);
    opacity: 0.65;
  }
  50% {
    transform: translateX(16rpx);
    opacity: 1;
  }
  100% {
    transform: translateX(0);
    opacity: 0.65;
  }
}

@keyframes twinkle {
  0% {
    opacity: 0.2;
    transform: scale(0.9);
  }
  50% {
    opacity: 1;
    transform: scale(1.2);
  }
  100% {
